"""
============================================================
МОДУЛЬ: models.py
============================================================
НАЗНАЧЕНИЕ: Определение моделей данных для системы учета сотрудников

АВТОР: Студент группы М3О-217БВ
ДАТА СОЗДАНИЯ: 2026-04-02
ПОСЛЕДНЕЕ ИЗМЕНЕНИЕ: 2026-04-02

ОПИСАНИЕ:
    Модуль содержит две основные модели:
    1. Emploees - хранит личную информацию о сотрудниках
    2. Logins - хранит учетные данные для входа в систему

ЗАВИСИМОСТИ:
    - django.db.models - для определения моделей БД
    - django.contrib.auth.hashers - для хеширования паролей
============================================================
"""

# Импорт модуля для определения моделей базы данных
from django.db import models
# Импорт функций для хеширования и проверки паролей
from django.contrib.auth.hashers import make_password,check_password


class Emploees(models.Model):
    """
    ============================================================
    КЛАСС: Emploees (Модель сотрудника)
    ============================================================
    НАЗНАЧЕНИЕ: Хранит личную информацию о сотрудниках фирмы
    
    ПОЛЯ:
        ROLE_CHOICES (list): Список возможных должностей (ролей доступа)
        last_name (CharField): Фамилия сотрудника
        first_name (CharField): Имя сотрудника
        patronymic (CharField): Отчество сотрудника (необязательное поле)
        position (CharField): Должность/роль сотрудника
        address (CharField): Адрес проживания сотрудника
        phone (CharField): Контактный телефон
        created_at (DateTimeField): Дата и время создания записи
        updated_at (DateTimeField): Дата и время последнего обновления
    
    МЕТОДЫ:
        __str__(): Возвращает строковое представление объекта
        full_name(): Свойство, возвращающее полное ФИО сотрудника
    
    АВТОР: Студент группы М3О-217БВ
    ДАТА: 2026-04-02
    ============================================================
    """

    """
    Список возможных должностей (ролей доступа)
    Используется для поля position
    Формат: (значение_в_БД, отображаемое_значение)
    """
    ROLE_CHOICES = [
        ('director', 'Директор'),
        ('deputy', 'Заместитель директора'),
        ('secretary', 'Секретарь'),
    ]
    # Поле для хранения фамилии сотрудника
    last_name = models.CharField('Фамилия', max_length=100)

    # Поле для хранения имени сотрудника
    first_name = models.CharField('Имя', max_length=100)

    # Поле для хранения отчества сотрудника (необязательное для заполнения)
    patronymic = models.CharField('Отчество', max_length=100, blank=True)

    # Поле для хранения должности сотрудника
    # choices=ROLE_CHOICES - ограничивает выбор значениями из списка ROLE_CHOICES
    position = models.CharField('Должность',choices=ROLE_CHOICES,max_length=100)

    # Поле для хранения адреса сотрудника
    address = models.CharField('Адрес', max_length=300)

    # Поле для хранения телефона сотрудника
    phone = models.CharField('Телефон', max_length=20)

    # Поле для хранения даты создания записи
    # auto_now_add=True - автоматически устанавливает текущую дату и время при создании
    created_at = models.DateTimeField('Дата создания', auto_now_add=True)

    # Поле для хранения даты последнего обновления
    # auto_now=True - автоматически обновляется при каждом сохранении объекта
    updated_at = models.DateTimeField('Дата обновления', auto_now=True)

    @property
    def full_name(self):
        """
        ========================================================
        СВОЙСТВО: full_name
        ========================================================
        НАЗНАЧЕНИЕ: Возвращает полное ФИО сотрудника
        
        ВОЗВРАЩАЕТ:
            str: Фамилия, Имя, Отчество объединенные через пробел
        
        ПРИМЕР:
            employee = Emploees(last_name="Иванов", first_name="Иван", patronymic="Иванович")
            employee.full_name -> "Иванов Иван Иванович"
        
        ПРИМЕЧАНИЕ:
            Используется как свойство, поэтому вызывается без скобок
        ========================================================
        """
        return f'{self.last_name} {self.first_name} {self.patronymic}'.strip()
class Logins(models.Model):
    """
    ============================================================
    КЛАСС: Logins (Модель учетной записи)
    ============================================================
    НАЗНАЧЕНИЕ: Хранит учетные данные для входа в систему
    
    ПОЛЯ:
        employee (OneToOneField): Ссылка на сотрудника (связь один к одному)
        login (CharField): Уникальный логин пользователя
        password (CharField): Хешированный пароль пользователя
    
    СВЯЗИ:
        - OneToOneField: каждый сотрудник может иметь только одну учетную запись
        - on_delete=models.CASCADE: при удалении сотрудника удаляется учетная запись
        - related_name='account': позволяет обращаться через employee.account
    
    МЕТОДЫ:
        check_password(): Проверяет соответствие введенного пароля хешу
        set_password(): Устанавливает хешированный пароль
        save(): Переопределенный метод для автоматического хеширования
    
    АВТОР: Студент группы М3О-217БВ
    ДАТА: 2026-04-02
    ============================================================
    """

    # Поле для связи с сотрудником (один к одному)
    # Emploees - связанная модель
    # on_delete=models.CASCADE - при удалении сотрудника удалить учетную запись
    # verbose_name='Сотрудник' - отображаемое имя поля
    # related_name='account' - обратная связь: employee.account
    employee = models.OneToOneField(
        Emploees,
        on_delete=models.CASCADE,
        verbose_name='Сотрудник',
        related_name='account'
    )

    # Поле для хранения логина пользователя
    # unique=True - запрещает дублирование логинов в базе данных
    login = models.CharField('Логин', max_length=100, unique=True) 

    # Поле для хранения хешированного пароля
    # Длина 255 символов достаточна для хранения хеша (обычно 128-150 символов)
    password = models.CharField('Пароль', max_length=255)
    

    def check_password(self, raw_password):
        """
        ========================================================
        МЕТОД: check_password
        ========================================================
        НАЗНАЧЕНИЕ: Проверяет соответствие введенного пароля сохраненному хешу
        
        ПАРАМЕТРЫ:
            raw_password (str): Пароль введенный пользователем (не хешированный)
        
        ВОЗВРАЩАЕТ:
            bool: True - пароль верный, False - пароль неверный
        
        АЛГОРИТМ:
            1. Функция check_password() из Django хеширует raw_password
            2. Сравнивает полученный хеш с сохраненным в БД self.password
            3. Возвращает результат сравнения
        
        ПРИМЕР:
            if user.check_password("mypassword123"):
                print("Пароль верный")
        ========================================================
        """
        return check_password(raw_password, self.password)
    
    def set_password(self, raw_password):
        """
        ========================================================
        МЕТОД: set_password
        ========================================================
        НАЗНАЧЕНИЕ: Устанавливает хешированный пароль для учетной записи
        
        ПАРАМЕТРЫ:
            raw_password (str): Пароль в открытом виде (без хеширования)
        
        ВОЗВРАЩАЕТ:
            None
            
        АЛГОРИТМ:
            1. make_password() хеширует переданный пароль с использованием PBKDF2
            2. Сохраняет хеш в поле self.password
        
        ПРИМЕР:
            user.set_password("mypassword123")
            user.save()
        ========================================================
        """
        self.password = make_password(raw_password)

    def save(self, *args, **kwargs):
        """
        ========================================================
        МЕТОД: save (переопределенный)
        ========================================================
        НАЗНАЧЕНИЕ: Переопределяет стандартный метод save для автоматического
                    хеширования пароля перед сохранением в БД
        
        ПАРАМЕТРЫ:
            *args: Произвольные позиционные аргументы
            **kwargs: Произвольные именованные аргументы
        
        ВОЗВРАЩАЕТ:
            None
        
        ПРИМЕЧАНИЕ:
            Проверяет, не захеширован ли уже пароль по префиксу 'pbkdf2_sha256'
            Если не захеширован - хеширует автоматически
            
        ИСТОРИЯ ИЗМЕНЕНИЙ:
            2026-04-02: Создание метода
        ========================================================
        """
        if self.password and not self.password.startswith('pbkdf2_sha256'):
            self.password = make_password(self.password)
        super().save(*args, **kwargs)